const data = msg.payload || {};

// Travas de segurança: evita envio de 'undefined' se o Python estiver defasado
const engineStatus = data.engineStatus || "OFF";
const speed = typeof data.speed === 'number' ? data.speed : 0.0;
const fuelInstant = typeof data.fuelInstant === 'number' ? data.fuelInstant : 0.0;
const fuelEfficiency = typeof data.fuelEfficiency === 'number' ? data.fuelEfficiency : 0.0;

// Regra de negócio (Alerta de Desperdício)
const isWasting = (speed === 0 && engineStatus === "IDLE");

msg.headers = { 
    "Content-Type": "application/json"
};

// Arquitetura Upsert (Batch) para o Orion
msg.payload = {
    "actionType": "append",
    "entities": [
        {
            "id": "MiningTruck:001",
            "type": "Vehicle",
            "engineStatus": { "type": "Text", "value": engineStatus },
            "speed": { "type": "Number", "value": speed },
            "fuelInstant": { "type": "Number", "value": fuelInstant },
            "fuelEfficiency": { "type": "Number", "value": fuelEfficiency },
            "wasteAlert": { "type": "Boolean", "value": isWasting }
        }
    ]
};

return msg;
